    .container {
      width: 100%;
      padding: 20px;
      background-color: #f8f9fa;
    }

    .card {
      border-radius: 4px;
      box-shadow: 0 4px 6px rgba(0, 0, 0, 0.1);
      margin-bottom: 20px;
    }

    .card-title {
      font-size: 24px;
      margin-bottom: 10px;
    }

    .card-text {
      font-size: 16px;
    }
```

